    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0xBB2C7F1EF95CE42FULL + 0xE26516CA730C5A4BULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseC(pNonce * 0x8CA1C5A0F507AFF3ULL + 0xB3F330BE2D911B72ULL);
