    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0x93648455A063CAF7ULL + 0xD9FE79FD094CEB2CULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseA(pNonce * 0xF06AED68ABEAEA1DULL + 0xAE74E45980AB1869ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xFF13E7B4AE2EE32FULL + 0x9EFB877C75FF7B53ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0xA48DF6820B461307ULL + 0xDC7B77CC22406B5BULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xE5B18D0BA7F3253DULL + 0xE969EBFB118BE3C3ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseB(pNonce * 0xE64FCBEFA40F0375ULL + 0xF8E40E25C506B504ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0x9D1E8284B27BFA3DULL + 0xBE5E50C287DB413FULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0x8A3424C82FA45521ULL + 0xDD2C616A70FA3005ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseC(pNonce * 0xAE886728D685DC95ULL + 0xFA50F765107A8A6FULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseB(pNonce * 0x8668AD8A4212FC63ULL + 0xAD215CFE831A7C3CULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseC(pNonce * 0xBD658C70754AB269ULL + 0xA09E2F6537EE0E4DULL);
