            aOrbiterG = ((aOrbiterG + aOrbiterC) + 14012352726035843357U) + aOrbiterUpdateSaltD[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 5119918287048876511U;
            aOrbiterD = RotL64((aOrbiterD * 15546330885001240897U), 43U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterJ) + 10535332810957727956U;
            aOrbiterA = (aOrbiterA ^ aOrbiterF) ^ 4472312678102438758U;
            aOrbiterA = RotL64((aOrbiterA * 12138527017419246525U), 21U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterD) + 11293609421067091154U) + aOrbiterUpdateSaltA[((aIndex + 5U)) & S_SALT1];
            aOrbiterH = ((aOrbiterH ^ aOrbiterB) ^ 11506840160235504596U) ^ aOrbiterUpdateSaltB[((aIndex + 4U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 16540535592045074973U), 23U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterF) + 13489596077185284847U;
            aOrbiterE = (aOrbiterE ^ aOrbiterD) ^ 15168923608198593801U;
            aOrbiterE = RotL64((aOrbiterE * 16282866382394080129U), 41U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterI) + 5638271625657180234U) + aOrbiterUpdateSaltE[(((31U - aIndex) + 20U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 1615833435348737589U;
            aOrbiterF = RotL64((aOrbiterF * 13802506008163828485U), 51U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterH) + 910548937071747567U;
            aOrbiterK = (aOrbiterK ^ aOrbiterJ) ^ 2187545732270929838U;
