            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 15525252000795392088U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterI) ^ 7876344738181067968U;
            aOrbiterJ = RotL64((aOrbiterJ * 12565542296063944021U), 35U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterE) + 5658395778980096939U;
            aOrbiterG = (aOrbiterG ^ aOrbiterH) ^ 18181242460668474909U;
            aOrbiterG = RotL64((aOrbiterG * 12066872753922893503U), 53U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterA) + 1810743701189482372U;
            aOrbiterC = (aOrbiterC ^ aOrbiterE) ^ 5428895436004468937U;
            aOrbiterC = RotL64((aOrbiterC * 8139604258221531773U), 39U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 17500820233998265286U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterK) ^ 7388667641335874954U) ^ aNonceWordN;
            aOrbiterB = RotL64((aOrbiterB * 4186268885165154663U), 57U);
            //
            aIngress = RotL64(aOrbiterF, 35U) ^ aOrbiterH;
            aIngress = aIngress + (RotL64(aOrbiterE, 43U) ^ aOrbiterJ);
            aIngress = aIngress + (RotL64(aOrbiterA, 10U) ^ aOrbiterC);
            aIngress = aIngress + (RotL64(aOrbiterB, 57U) ^ aOrbiterD);
            aIngress = aIngress + (RotL64(aOrbiterG, 21U) ^ aOrbiterI);
            aIngress = aIngress + RotL64(aOrbiterK, 27U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererG = aWandererG ^ ((((RotL64(aScatter, 3U) + RotL64(aOrbiterG, 35U)) + aOrbiterH) + aNonceWordM) + aWandererUpdateSaltA[(((31U - aIndex) + 23U)) & S_SALT1]);
            aWandererC = aWandererC + ((RotL64(aCross, 35U) + RotL64(aOrbiterJ, 19U)) + aOrbiterE);
            aWandererK = aWandererK ^ ((RotL64(aIngress, 13U) + aOrbiterA) + RotL64(aOrbiterG, 21U));
            aWandererA = aWandererA + (((RotL64(aPrevious, 37U) + aOrbiterC) + RotL64(aOrbiterI, 11U)) + aNonceWordH);
